import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, handleLogout }) => {
    // State untuk melacak hover pada setiap tombol
    const [hovered, setHovered] = useState(null);

    const navigateTo = (menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
    };

    // Style helper untuk konsistensi
    const getButtonStyle = (menuId) => ({
        background: 'none',
        border: 'none',
        color: activeMenu === menuId || hovered === menuId ? '#f59e0b' : '#fff',
        fontWeight: '700',
        fontSize: '14px',
        cursor: 'pointer',
        transition: 'all 0.3s ease',
        transform: hovered === menuId ? 'scale(1.05)' : 'scale(1)',
    });

    return (
        <nav style={{ 
            display: 'flex', justifyContent: 'space-between', alignItems: 'center', 
            padding: '20px 80px', background: '#0c0a09', borderBottom: '1px solid #262626' 
        }}>
            <div onClick={() => navigateTo('home')} style={{ cursor: 'pointer' }}>
                <h1 style={{ color: '#ea580c', margin: 0, fontSize: '24px' }}>PasukanYerusSolo</h1>
            </div>

            <div style={{ display: 'flex', gap: '24px', alignItems: 'center' }}>
                <Link to="/" 
                    style={{ ...getButtonStyle('home'), textDecoration: 'none' }}
                    onMouseEnter={() => setHovered('home')}
                    onMouseLeave={() => setHovered(null)}
                >Home</Link>

                <button 
                    onClick={() => navigateTo('eksplorasi')}
                    style={getButtonStyle('eksplorasi')}
                    onMouseEnter={() => setHovered('eksplorasi')}
                    onMouseLeave={() => setHovered(null)}
                >Eksplorasi</button>

                {isAuthenticated ? (
                    <>
                        <button onClick={() => navigateTo('favorit')} style={getButtonStyle('favorit')} onMouseEnter={() => setHovered('favorit')} onMouseLeave={() => setHovered(null)}>Favorit</button>
                        <button onClick={() => navigateTo('status')} style={getButtonStyle('status')} onMouseEnter={() => setHovered('status')} onMouseLeave={() => setHovered(null)}>Status</button>
                        <button onClick={handleLogout} 
                            style={{ 
                                padding: '8px 20px', borderRadius: '20px', border: '1px solid #ef4444', 
                                background: hovered === 'keluar' ? '#ef4444' : 'transparent', 
                                color: hovered === 'keluar' ? '#fff' : '#ef4444', 
                                fontWeight: '700', cursor: 'pointer', transition: '0.3s' 
                            }}
                            onMouseEnter={() => setHovered('keluar')}
                            onMouseLeave={() => setHovered(null)}
                        >Keluar</button>
                    </>
                ) : (
                    <button 
                        onClick={() => window.location.href = '/login'}
                        style={{ 
                            padding: '8px 20px', borderRadius: '20px', border: '1px solid #ea580c', 
                            background: hovered === 'login' ? '#ea580c' : 'transparent', 
                            color: hovered === 'login' ? '#fff' : '#ea580c', 
                            fontWeight: '700', cursor: 'pointer', transition: '0.3s' 
                        }}
                        onMouseEnter={() => setHovered('login')}
                        onMouseLeave={() => setHovered(null)}
                    >Login</button>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
